class Student:
    # Class variable (shared by all)
    school = 'Python Academy'

    def __init__(self, name, marks):
        # Instance variables (unique to each object)
        self.name = name
        self.marks = marks

    def grade(self):
        if self.marks >= 90:
            return 'A'
        elif self.marks >= 75:
            return 'B'
        else:
            return 'C'

    def __str__(self):
        return f'{self.name} - {self.marks} ({self.grade()})'

s1 = Student('Aryan', 92)
s2 = Student('Ravi', 78)

print(s1)
print(s2)
print('School:', Student.school)

class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        return 'Some sound'

    def __str__(self):
        return f'{self.name} ({self.__class__.__name__})'

class Dog(Animal):
    def speak(self):
        return 'Woof!'

class Cat(Animal):
    def speak(self):
        return 'Meow!'

class Duck(Animal):
    def speak(self):
        return 'Quack!'

animals = [Dog('Bruno'), Cat('Whiskers'), Duck('Donald')]
for animal in animals:
    print(f'{animal} says: {animal.speak()}')

import time

# Simple decorator
def shout(func):
    def wrapper(*args, **kwargs):
        print('--- START ---')
        result = func(*args, **kwargs)
        print('--- END ---')
        return result
    return wrapper

@shout
def greet(name):
    print(f'Hello, {name}!')

greet('Aryan')

print()

# Timer decorator
def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'{func.__name__} took {end-start:.4f}s')
        return result
    return wrapper

@timer
def count_up(n):
    total = 0
    for i in range(n):
        total += i
    return total

print(count_up(1000000))

# Bubble Sort
def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        for j in range(0, n-i-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
    return arr

# Quick Sort
def quick_sort(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr)//2]
    left = [x for x in arr if x < pivot]
    mid = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return quick_sort(left) + mid + quick_sort(right)

nums = [64, 34, 25, 12, 22, 11, 90]
print('Original:', nums)
print('Bubble Sort:', bubble_sort(nums.copy()))
print('Quick Sort:', quick_sort(nums))
